            'iab_notice_description' => '<p>ئێمه‌ و <button id="cnzIABNoticeButton" class="cnz-iab-dec-btn" aria-label="partners">{vendor_count} هاوبه‌ش</button> کووکییه‌کان و ته‌کنه‌لۆژیای دیکه‌ی چاودێری به‌کار ده‌هێنین بۆ باشترکردنی ئه‌زموونی تۆ له‌سه‌ر وێبسایته‌که‌مان. ڕه‌نگه‌ زانیارییه‌ک له‌سه‌ر ئامێرێک هه‌ڵبگرین و/یان ده‌ستمان بگاتێ و داتا که‌سییه‌کان پرۆسێس بکه‌ین، وه‌ک ئای پی ئه‌درێسی تۆ و داتای گه‌ڕان، بۆ ڕیکلام و ناوه‌ڕۆکی تایبه‌تکراو، ڕیکلام و پێوانی ناوه‌ڕۆک، لێکۆڵینه‌وه‌ی بینه‌ران و په‌ره‌پێدانی خزمه‌تگوزارییه‌کان. هه‌روه‌ها، ڕه‌نگه‌ داتای شوێنی جوگرافی ورد و ناسینه‌وه‌ له‌ ڕێگه‌ی سکانکردنی ئامێره‌وه‌ به‌کاربهێنین.</p><p>تکایه‌ ئاگادارببه‌ که‌ ڕه‌زامه‌ندییه‌که‌ت له‌ سه‌رجه‌م ژێرده‌مینه‌کانماندا کارا ده‌بێت. ده‌توانیت له‌ هه‌ر کاتێکدا ڕه‌زامه‌ندییه‌که‌ت بگۆڕیت یان هه‌ڵیبوه‌شێنیته‌وه‌ به‌ کلیک کردن له‌سه‌ر دوگمه‌ی "تایبه‌تمه‌ندییه‌کانی ڕه‌زامه‌ندی" له‌ به‌شی خواره‌وه‌ی شاشه‌که‌ت. ئێمه‌ ڕێز له‌ هه‌ڵبژاردنه‌کانت ده‌گرین و پابه‌ندین به‌ دابینکردنی ئه‌زموونێکی گه‌ڕانی ڕوون و پارێزراو بۆ تۆ.</p>',
            'iab_preference_description' => '<p>تایبه‌تمه‌ندییه‌کانی ڕه‌زامه‌ندییه‌که‌ت بۆ پۆله‌کانی کووکی و تایبه‌تمه‌ندییه‌کانی چاودێریکردنی ڕیکلام بۆ مه‌به‌سته‌کان و تایبه‌تمه‌ندییه‌کان و فرۆشیاران له‌ خواره‌وه‌ گونجاو بکه‌. ده‌توانیت ڕه‌زامه‌ندی ورد بۆ هه‌ر <button id="cnzIABPreferenceButton" class="cnz-iab-dec-btn" aria-label="Third Party Vendor">فرۆشیاری لایه‌نی سێیه‌م</button> و <button id="cnzIABGACMPreferenceButton" class="cnz-iab-dec-btn" aria-label="Google Ad Tech Provider">دابینکه‌ری ته‌کنه‌لۆژیای ڕیکلامی گووگڵ</button> بده‌یت. زۆربه‌ی فرۆشیاران پێویستیان به‌ ڕه‌زامه‌ندییه‌ بۆ پرۆسێسکردنی داتا که‌سییه‌کان، له‌ کاتێکدا هه‌ندێکیان پشت به‌ به‌رژه‌وه‌ندی ڕه‌وا ده‌به‌ستن. به‌ڵام تۆ مافی ئه‌وه‌ت هه‌یه‌ که‌ دژی به‌کارهێنانی به‌رژه‌وه‌ندی ڕه‌وایان بوەستیته‌وه‌.</p>',
